func calc1(s string) int {
	res := 0
	n := len(s)
	i := 0
	for i < n {
		j := i + 1
		for j < n && s[j] == s[i] {
			j++
		}
		if j-i > res {
			res = j - i
		}
		i = j
	}
	return res
}

func calc2(s string, a, b byte) int {
	res := 0
	n := len(s)
	i := 0
	for i < n {
		for i < n && s[i] != a && s[i] != b {
			i++
		}
		pos := map[int]int{0: i - 1}
		d := 0
		for i < n && (s[i] == a || s[i] == b) {
			if s[i] == a {
				d++
			} else {
				d--
			}
			if prev, ok := pos[d]; ok {
				if i-prev > res {
					res = i - prev
				}
			} else {
				pos[d] = i
			}
			i++
		}
	}
	return res
}

type key struct {
