}

func calc3(s string) int {
	pos := make(map[key]int)
	pos[key{0, 0}] = -1

	cnt := [3]int{}
	res := 0

	for i := 0; i < len(s); i++ {
		c := s[i]
		cnt[c-'a']++
		x := cnt[0] - cnt[1]
		y := cnt[1] - cnt[2]
		k := key{x, y}

		if j, ok := pos[k]; ok {
			if i-j > res {
				res = i - j
			}
		} else {
			pos[k] = i
		}
	}
	return res
}

